import{_ as o,o as a,c,a2 as d}from"./chunks/framework.BRk9mohw.js";const u=JSON.parse('{"title":"桥接协议（遗留节点传输）","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gateway/bridge-protocol.md","filePath":"tools/gateway/bridge-protocol.md"}'),l={name:"tools/gateway/bridge-protocol.md"};function i(t,e,r,n,s,h){return a(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="桥接协议-遗留节点传输" tabindex="-1">桥接协议（遗留节点传输） <a class="header-anchor" href="#桥接协议-遗留节点传输" aria-label="Permalink to &quot;桥接协议（遗留节点传输）&quot;">​</a></h1><p>桥接协议是一个<strong>遗留</strong>节点传输（TCP JSONL）。新节点客户端应改用统一的网关 WebSocket 协议。</p><p>如果你正在构建 operator 或节点客户端，请使用 <a href="/gateway/protocol.html">Gateway protocol</a>。</p><p><strong>注意：</strong> 当前 OpenClaw 构建不再包含 TCP 桥接监听器；保留此文档用于历史参考。旧的 <code>bridge.*</code> 配置键不再是配置模式的一部分。</p><h2 id="为什么两者都有" tabindex="-1">为什么两者都有 <a class="header-anchor" href="#为什么两者都有" aria-label="Permalink to &quot;为什么两者都有&quot;">​</a></h2><ul><li><strong>安全边界</strong>：桥接暴露一个小允许列表而非完整网关 API 表面。</li><li><strong>配对 + 节点身份</strong>：节点 admission 由网关拥有并绑定到每个节点的令牌。</li><li><strong>发现 UX</strong>：节点可以通过 LAN 上的 Bonjour 或直接通过 tailnet 连接发现网关。</li><li><strong>环回 WS</strong>：完整 WS 控制平面保持本地，除非通过 SSH 隧道。</li></ul><h2 id="传输" tabindex="-1">传输 <a class="header-anchor" href="#传输" aria-label="Permalink to &quot;传输&quot;">​</a></h2><ul><li>TCP，每行一个 JSON 对象（JSONL）。</li><li>可选 TLS（当 <code>bridge.tls.enabled</code> 为 true 时）。</li><li>遗留默认监听端口是 <code>18790</code>（当前构建不启动 TCP 桥接）。</li></ul><p>启用 TLS 时，发现 TXT 记录包括 <code>bridgeTls=1</code> 加上 <code>bridgeTlsSha256</code> 作为非秘密提示。注意 Bonjour/mDNS TXT 记录是未认证的；客户端不得将广告的指纹视为权威固定，除非有明确的用户意图或其他带外验证。</p><h2 id="握手-配对" tabindex="-1">握手 + 配对 <a class="header-anchor" href="#握手-配对" aria-label="Permalink to &quot;握手 + 配对&quot;">​</a></h2><ol><li>客户端发送带有节点元数据 + 令牌的 <code>hello</code>（如果已配对）。</li><li>如果未配对，网关回复 <code>error</code>（<code>NOT_PAIRED</code>/<code>UNAUTHORIZED</code>）。</li><li>客户端发送 <code>pair-request</code>。</li><li>网关等待批准，然后发送 <code>pair-ok</code> 和 <code>hello-ok</code>。</li></ol><p><code>hello-ok</code> 返回 <code>serverName</code>，可能包括 <code>canvasHostUrl</code>。</p><h2 id="帧" tabindex="-1">帧 <a class="header-anchor" href="#帧" aria-label="Permalink to &quot;帧&quot;">​</a></h2><p>客户端 → 网关：</p><ul><li><code>req</code> / <code>res</code>：作用域网关 RPC（chat、sessions、config、health、voicewake、skills.bins）</li><li><code>event</code>：节点信号（voice transcript、agent request、chat subscribe、exec lifecycle）</li></ul><p>网关 → 客户端：</p><ul><li><code>invoke</code> / <code>invoke-res</code>：节点命令（<code>canvas.*</code>、<code>camera.*</code>、<code>screen.record</code>、<code>location.get</code>、<code>sms.send</code>）</li><li><code>event</code>：订阅会话的聊天更新</li><li><code>ping</code> / <code>pong</code>：保活</li></ul><p>遗留允许列表强制执行在 <code>src/gateway/server-bridge.ts</code> 中（已移除）。</p><h2 id="exec-生命周期事件" tabindex="-1">Exec 生命周期事件 <a class="header-anchor" href="#exec-生命周期事件" aria-label="Permalink to &quot;Exec 生命周期事件&quot;">​</a></h2><p>节点可以发出 <code>exec.finished</code> 或 <code>exec.denied</code> 事件以浮现 system.run 活动。这些映射到网关中的系统事件。（遗留节点可能仍发出 <code>exec.started</code>。）</p><p>有效载荷字段（全部可选，除非注明）：</p><ul><li><code>sessionKey</code>（必需）：接收系统事件的代理会话。</li><li><code>runId</code>：分组的唯一 exec id。</li><li><code>command</code>：原始或格式化的命令字符串。</li><li><code>exitCode</code>、<code>timedOut</code>、<code>success</code>、<code>output</code>：完成详情（仅 finished）。</li><li><code>reason</code>：拒绝原因（仅 denied）。</li></ul><h2 id="tailnet-使用" tabindex="-1">Tailnet 使用 <a class="header-anchor" href="#tailnet-使用" aria-label="Permalink to &quot;Tailnet 使用&quot;">​</a></h2><ul><li>绑定桥接到 tailnet IP：在 <code>~/.openclaw/openclaw.json</code> 中设置 <code>bridge.bind: &quot;tailnet&quot;</code>。</li><li>客户端通过 MagicDNS 名称或 tailnet IP 连接。</li><li>Bonjour <strong>不</strong>跨网络；需要时使用手动主机/端口或广域网 DNS-SD。</li></ul><h2 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h2><p>桥接当前为<strong>隐式 v1</strong>（无 min/max 协商）。预期向后兼容；在任何重大更改之前添加桥接协议版本字段。</p>',26)])])}const g=o(l,[["render",i]]);export{u as __pageData,g as default};
